CREATE FUNCTION public.batch_generate_embeddings(batch_size integer DEFAULT 100) RETURNS TABLE(processed_count bigint, remaining_count bigint)
    LANGUAGE plpgsql
    AS $$ BEGIN RETURN QUERY WITH updated AS (UPDATE simple_blog_posts SET content_embedding = content_embedding WHERE content_embedding IS NULL AND status = 'published' RETURNING 1) SELECT COUNT(*)::BIGINT as processed_count, (SELECT COUNT(*) FROM simple_blog_posts WHERE content_embedding IS NULL AND status = 'published')::BIGINT as remaining_count FROM updated LIMIT batch_size; END; $$;


