    AS $$ BEGIN RETURN QUERY SELECT t.id, t.title, t.content, COALESCE(ts_rank(t.content_zh_vector, plainto_tsquery('chinese', query_text)), 0)::REAL as ts_rank_score, COALESCE(1 - (t.content_embedding <=> query_vector), 0)::REAL as similarity, (COALESCE(ts_rank(t.content_zh_vector, plainto_tsquery('chinese', query_text)), 0) * 0.3 + (1 - (t.content_embedding <=> query_vector)) * 0.7)::REAL as combined_score FROM simple_blog_posts t WHERE (t.content_zh_vector @@ plainto_tsquery('chinese', query_text) OR t.content_embedding IS NOT NULL) AND t.status = 'published' ORDER BY combined_score DESC LIMIT limit_count; END; $$;


