    LANGUAGE plpgsql
    AS $$
BEGIN
    NEW.content_vector = to_tsvector('chinese',
        COALESCE(NEW.title, '') || ' ' ||
        COALESCE(NEW.description, '') || ' ' ||
        COALESCE(NEW.content, '')
    );
    RETURN NEW;
END;
$$;


