CREATE TABLE public.jianhui_org_articles (
    id bigint NOT NULL,
    category_id bigint,
    original_id character varying(50),
    title character varying(500),
    slug character varying(500),
    description text,
    content text,
    content_vector tsvector,
    cover_image character varying(500),
    author character varying(100),
    source_url character varying(500),
    published_date date,
    status public.article_status DEFAULT 'published'::public.article_status,
    view_count integer DEFAULT 0,
    is_featured boolean DEFAULT false,
    is_pinned boolean DEFAULT false,
    sort_order integer DEFAULT 0,
    metadata jsonb,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    CONSTRAINT chk_title_not_empty CHECK ((length(TRIM(BOTH FROM title)) > 0)),
    CONSTRAINT chk_view_count_non_negative CHECK ((view_count >= 0))
);


