--
-- Name: jianhui_articles_by_category_view; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.jianhui_articles_by_category_view AS
 SELECT category_id,
    count(*) AS article_count,
    max(published_date) AS latest_date
   FROM public.jianhui_org_articles
  WHERE ((status = 'published'::public.article_status) AND (category_id IS NOT NULL))
  GROUP BY category_id
  ORDER BY (count(*)) DESC;


ALTER VIEW public.jianhui_articles_by_category_view OWNER TO postgres;

--
-- Name: jianhui_articles_featured_view; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.jianhui_articles_featured_view AS
 SELECT id,
    category_id,
    original_id,
    title,
    slug,
    description,
    content,
    content_vector,
    cover_image,
    author,
    source_url,
    published_date,
    status,
    view_count,
    is_featured,
    is_pinned,
    sort_order,
    metadata,
    created_at,
    updated_at
   FROM public.jianhui_org_articles
  WHERE ((status = 'published'::public.article_status) AND (is_featured = true))
  ORDER BY published_date DESC;


ALTER VIEW public.jianhui_articles_featured_view OWNER TO postgres;

