CREATE VIEW public.jianhui_articles_published_view AS
 SELECT id,
    category_id,
    original_id,
    title,
    slug,
    description,
    content,
    content_vector,
    cover_image,
    author,
    source_url,
    published_date,
    status,
    view_count,
    is_featured,
    is_pinned,
    sort_order,
    metadata,
    created_at,
    updated_at
   FROM public.jianhui_org_articles
  WHERE (status = 'published'::public.article_status)
  ORDER BY is_pinned DESC, published_date DESC, created_at DESC;


ALTER VIEW public.jianhui_articles_published_view OWNER TO postgres;

--
-- Name: jianhui_articles_recent_view; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.jianhui_articles_recent_view AS
 SELECT id,
    title,
    description,
    category_id,
    published_date,
    cover_image
   FROM public.jianhui_org_articles
  WHERE (status = 'published'::public.article_status)
  ORDER BY published_date DESC, created_at DESC
 LIMIT 10;


ALTER VIEW public.jianhui_articles_recent_view OWNER TO postgres;

