CREATE VIEW public.jianhui_lifestories_by_location_view AS
 SELECT person_location,
    count(*) AS story_count
   FROM public.jianhui_org_life_stories
  WHERE ((status = 'published'::public.article_status) AND (person_location IS NOT NULL))
  GROUP BY person_location
  ORDER BY (count(*)) DESC;


